import { useEffect, useMemo, useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import { deleteVehicle, getVehicles } from "../../api/vehicleApi";
import { getAuth } from "../../utils/auth";

export default function VehicleList() {
  const [vehicles, setVehicles] = useState([]);
  const [typeFilter, setTypeFilter] = useState("all");
  const [loading, setLoading] = useState(false);

  const navigate = useNavigate();

  const auth = getAuth();
  const role = auth?.role;
  const canManageVehicles = role === "admin" || role === "manager";

  const load = async () => {
    setLoading(true);
    try {
      const res = await getVehicles();
      setVehicles(res.data || []);
    } catch (err) {
      alert(err.response?.data?.message || "Failed to load vehicles");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    load();
  }, []);

  const vehicleTypes = useMemo(() => {
    const s = new Set(vehicles.map((v) => v.type).filter(Boolean));
    return ["all", ...Array.from(s)];
  }, [vehicles]);

  const filtered = useMemo(() => {
    if (typeFilter === "all") return vehicles;
    return vehicles.filter((v) => v.type === typeFilter);
  }, [vehicles, typeFilter]);

  const bookNow = (vehicleId, status) => {
    if (status !== "available") return alert("This vehicle is not available for booking.");
    if (!localStorage.getItem("token")) {
      alert("Please login to book an appointment.");
      return navigate("/login");
    }
    navigate("/book-appointment", { state: { vehicleId } });
  };

  const onDelete = async (id) => {
    if (!canManageVehicles) return alert("Access denied");
    if (!window.confirm("Delete this vehicle permanently?")) return;

    try {
      await deleteVehicle(id);
      setVehicles((prev) => prev.filter((v) => v._id !== id));
      alert("Vehicle deleted");
    } catch (err) {
      alert(err.response?.data?.message || "Delete failed");
    }
  };

  const badgeClass = (status) => {
    if (status === "available") return "badge badgeOk";
    if (status === "reserved") return "badge badgeWarn";
    if (status === "sold") return "badge badgeBad";
    return "badge";
  };

  const getCover = (v) => v?.images?.[0]?.url || "";

  return (
    <div className="container">
      <div className="card cardPad">
        <div className="row">
          <div>
            <h2 className="h1">Vehicles</h2>
            <div className="sub">Inventory overview</div>
          </div>

          <div style={{ display: "flex", gap: 10, alignItems: "center", flexWrap: "wrap" }}>
            <select
              className="select"
              style={{ width: 220 }}
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
            >
              {vehicleTypes.map((t) => (
                <option key={t} value={t}>
                  {t === "all" ? "All Types" : t}
                </option>
              ))}
            </select>

            <button className="btn" onClick={load} disabled={loading}>
              {loading ? "Loading..." : "Refresh"}
            </button>

            {canManageVehicles && (
              <Link className="btn btnPrimary" to="/vehicles/add">
                + Add Vehicle
              </Link>
            )}
          </div>
        </div>
      </div>

      <div style={{ marginTop: 14, display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 12 }}>
        {filtered.map((v) => {
          const cover = getCover(v);

          return (
            <div key={v._id} className="card" style={{ overflow: "hidden" }}>
              {/* ✅ Cover Image 4:3 */}
              <div style={{ width: "100%", aspectRatio: "4 / 3", background: "#f3f4f6" }}>
                {cover ? (
                  <img
                    src={cover}
                    alt="cover"
                    style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }}
                  />
                ) : (
                  <div style={{ height: "100%", display: "grid", placeItems: "center", color: "#6b7280" }}>
                    No Photo
                  </div>
                )}
              </div>

              <div className="cardPad">
                <div className="row" style={{ alignItems: "flex-start" }}>
                  <div>
                    <div style={{ fontWeight: 900, fontSize: 16 }}>
                      {v.brand} {v.model || ""}
                    </div>
                    <div className="sub">
                      {v.type} • {v.year}
                      {v.vehicleNumber ? ` • ${v.vehicleNumber}` : ""}
                    </div>
                  </div>
                  <span className={badgeClass(v.status)}>{v.status}</span>
                </div>

                <div style={{ marginTop: 10, fontWeight: 800, fontSize: 18 }}>
                  Rs. {Number(v.price || 0).toLocaleString()}
                </div>

                <div style={{ marginTop: 12, display: "flex", gap: 10, flexWrap: "wrap" }}>
                  <button className="btn" onClick={() => bookNow(v._id, v.status)} disabled={v.status !== "available"}>
                    Book Appointment
                  </button>

                  {canManageVehicles && (
                    <>
                      <button className="btn" onClick={() => navigate(`/vehicles/edit/${v._id}`)}>
                        Edit
                      </button>
                      <button className="btn btnDanger" onClick={() => onDelete(v._id)}>
                        Delete
                      </button>
                    </>
                  )}
                </div>
              </div>
            </div>
          );
        })}

        {!loading && filtered.length === 0 && (
          <div className="card cardPad" style={{ gridColumn: "1 / -1" }}>
            <div className="muted">No vehicles found.</div>
          </div>
        )}
      </div>
    </div>
  );
}
